/**
 * Clean reimplementation of the obfuscated physics simulation.
 *
 * What it does:
 * - Simulates a small network of nodes
 * - Applies pairwise attraction between all nodes
 * - Applies spring constraints between selected node pairs
 * - Applies mild centering pull toward (400, 300)
 * - Applies damping to node velocity
 * - Spawns drifting particles from random nodes
 * - Smoothly eases a camera toward a target camera
 * - Advances on a fixed interval
 */

const TAU = Math.PI * 2;
const GOLDEN_RATIO = 1.618;
const SQRT_HALF = 0.707;

const config = {
  attraction: 4000,
  springCoefficient: 0.004,
  damping: 0.92,
  centeringForce: 0.0003,

  maxParticles: 40,
  particleDecay: 0.04,

  cameraEase: 0.06,
};

const nodes = [
  { id: "hub",     label: "Hub",     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: "alpha",   label: "Alpha",   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: "beta",    label: "Beta",    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: "gamma",   label: "Gamma",   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: "delta",   label: "Delta",   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: "epsilon", label: "Epsilon", r: 12, x: 350, y: 150, vx: 0, vy: 0 },
];

const springs = [
  { a: "hub",   b: "alpha",   rest: 160, k: 0.006 },
  { a: "hub",   b: "beta",    rest: 160, k: 0.005 },
  { a: "hub",   b: "gamma",   rest: 170, k: 0.004 },
  { a: "hub",   b: "delta",   rest: 170, k: 0.004 },
  { a: "hub",   b: "epsilon", rest: 180, k: 0.003 },
  { a: "alpha", b: "beta",    rest: 200, k: 0.002 },
  { a: "gamma", b: "delta",   rest: 220, k: 0.002 },
  { a: "alpha", b: "epsilon", rest: 200, k: 0.002 },
];

const camera = {
  x: 400,
  y: 300,
  zoom: 1,
};

const targetCamera = {
  x: 400,
  y: 300,
  zoom: 1,
};

const particles = [];
let tickCount = 0;

function findNodeById(id) {
  return nodes.find(node => node.id === id) ?? null;
}

function updateNodePhysics() {
  // Pairwise attraction between every node pair.
  for (let i = 0; i < nodes.length; i++) {
    for (let j = i + 1; j < nodes.length; j++) {
      const a = nodes[i];
      const b = nodes[j];

      const dx = a.x - b.x;
      const dy = a.y - b.y;
      const distance = Math.sqrt(dx * dx + dy * dy) || 1;

      const force = config.attraction / (distance * distance);
      const fx = (dx / distance) * force;
      const fy = (dy / distance) * force;

      a.vx += fx;
      a.vy += fy;
      b.vx -= fx;
      b.vy -= fy;
    }
  }

  // Spring forces between selected node pairs.
  for (const spring of springs) {
    const a = findNodeById(spring.a);
    const b = findNodeById(spring.b);
    if (!a || !b) continue;

    const dx = b.x - a.x;
    const dy = b.y - a.y;
    const distance = Math.sqrt(dx * dx + dy * dy) || 1;

    const extension = distance - spring.rest;
    const force = (spring.k ?? config.springCoefficient) * extension;

    const fx = (dx / distance) * force;
    const fy = (dy / distance) * force;

    a.vx += fx;
    a.vy += fy;
    b.vx -= fx;
    b.vy -= fy;
  }

  // Damping, centering, and integration.
  for (const node of nodes) {
    node.vx += (400 - node.x) * config.centeringForce;
    node.vy += (300 - node.y) * config.centeringForce;

    node.vx *= config.damping;
    node.vy *= config.damping;

    node.x += node.vx;
    node.y += node.vy;
  }
}

function spawnParticle() {
  if (particles.length >= config.maxParticles) return;

  const source = nodes[Math.floor(Math.random() * nodes.length)];
  const angle = Math.random() * TAU;
  const speed = 0.3 + Math.random() * SQRT_HALF;

  particles.push({
    x: source.x,
    y: source.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * GOLDEN_RATIO * SQRT_HALF,
  });
}

function updateParticles() {
  const velocityDecay = 1 - config.particleDecay * 0.125;

  for (let i = particles.length - 1; i >= 0; i--) {
    const particle = particles[i];

    particle.age += 1;
    particle.vx *= velocityDecay;
    particle.vy *= velocityDecay;
    particle.x += particle.vx;
    particle.y += particle.vy;

    if (particle.age > particle.maxAge) {
      particles.splice(i, 1);
    }
  }
}

function updateCamera() {
  camera.x += (targetCamera.x - camera.x) * config.cameraEase;
  camera.y += (targetCamera.y - camera.y) * config.cameraEase;
  camera.zoom += (targetCamera.zoom - camera.zoom) * config.cameraEase;
}

function stepSimulation() {
  updateNodePhysics();
  updateParticles();
  updateCamera();

  if (tickCount % 3 === 0) {
    spawnParticle();
  }

  tickCount += 1;
}

setInterval(stepSimulation, 10);
